  updated_at = unixepoch();

CREATE TABLE IF NOT EXISTS vertical_synonyms (
  id                    TEXT PRIMARY KEY,
  canonical_slug        TEXT NOT NULL REFERENCES verticals(slug),
  synonym_slug          TEXT NOT NULL,
  related_vertical_slug TEXT REFERENCES verticals(slug),
  relation_type         TEXT NOT NULL CHECK (relation_type IN ('overlap','specialization','package_alias','external_alias')),
  resolution_notes      TEXT NOT NULL,
  created_at            INTEGER NOT NULL DEFAULT (unixepoch()),
  updated_at            INTEGER NOT NULL DEFAULT (unixepoch()),
  UNIQUE (canonical_slug, synonym_slug)
);

CREATE INDEX IF NOT EXISTS idx_vertical_synonyms_synonym ON vertical_synonyms(synonym_slug);
CREATE INDEX IF NOT EXISTS idx_vertical_synonyms_related ON vertical_synonyms(related_vertical_slug);

