  ('vsyn_mass_transit_transit', 'mass-transit', 'transit', 'mass-transit', 'package_alias', 'Registered slug is mass-transit while implementation package/profile table use transit naming.'),
  ('vsyn_photography_photography_studio', 'photography', 'photography-studio', 'photography', 'package_alias', 'Registered slug photography maps to photography-studio package/table naming.'),
  ('vsyn_event_hall_events_centre', 'event-hall', 'events-centre', 'events-centre', 'overlap', 'Use event-hall for generic venue seeding; events-centre is a related hall-rental variant.'),
  ('vsyn_beauty_salon_hair_salon', 'beauty-salon', 'hair-salon', 'hair-salon', 'overlap', 'Use beauty-salon for generic personal-care venues; hair-salon is a specialized hair/barbing variant.'),
  ('vsyn_pharmacy_pharmacy_chain', 'pharmacy', 'pharmacy-chain', 'pharmacy-chain', 'specialization', 'Use pharmacy for individual pharmacy outlets; pharmacy-chain represents multi-outlet operators.'),
  ('vsyn_restaurant_restaurant_chain', 'restaurant', 'restaurant-chain', 'restaurant-chain', 'specialization', 'Use restaurant for individual outlets; restaurant-chain represents multi-outlet brands.')
ON CONFLICT(canonical_slug, synonym_slug) DO UPDATE SET
  related_vertical_slug = excluded.related_vertical_slug,
  relation_type = excluded.relation_type,
  resolution_notes = excluded.resolution_notes,
  updated_at = unixepoch();

CREATE TABLE IF NOT EXISTS vertical_seedability_matrix (
  vertical_slug                TEXT PRIMARY KEY REFERENCES verticals(slug),
  profile_status              TEXT NOT NULL CHECK (profile_status IN ('exists','partial','missing')),
  profile_table               TEXT,
  profile_migration           TEXT,
  profile_column_count        INTEGER,
  requires_sidecar_enrichment INTEGER NOT NULL DEFAULT 1 CHECK (requires_sidecar_enrichment IN (0,1)),
  seedability_status          TEXT NOT NULL CHECK (seedability_status IN ('seedable_with_sidecar','manual_review_with_sidecar','profile_schema_missing')),
  seedability_notes           TEXT NOT NULL,
  created_at                  INTEGER NOT NULL DEFAULT (unixepoch()),
  updated_at                  INTEGER NOT NULL DEFAULT (unixepoch())
);

CREATE INDEX IF NOT EXISTS idx_vertical_seedability_status ON vertical_seedability_matrix(profile_status, seedability_status);
CREATE INDEX IF NOT EXISTS idx_vertical_seedability_sidecar ON vertical_seedability_matrix(requires_sidecar_enrichment);

